var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하하하! 뒤통수 맞은 기분이 어떠냐, 허접들아-!","JPN":"キャハハッ！　騙された気分はどうだ、ヘタクソどもー！","ENG":"Kya hah hah hah! I got you good, ya scurvy dogs!","TWN":"哇哈哈哈！笨蛋！被人擺一道的感覺怎麼樣啊？"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"선장님! 구하러 올 거라 믿었어요!","JPN":"船長！　助けに来てくださると信じていました！","ENG":"Captain! I knew you'd come save us!","TWN":"船長！我就知道你會來救我們！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_WATCH","text":{"KOREA":"크윽… 너희들, 이런 식으로 탈옥하고도 뒷감당을 할 수 있을 것 같아?","JPN":"くうっ……お前ら、こんな風に脱獄して大丈夫と思うのか？","ENG":"Kgh... You think you can handle the aftermath of breaking out?","TWN":"咳呃…你們用這種方式逃獄有辦法承擔後果嗎？"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L5_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_WATCH","text":{"KOREA":"프론트베이에선 어디로 도망쳐도 결국 관리국 손바닥 안이라고.","JPN":"フロントベイではどこへ逃げても結局は管理局の掌の中だ。","ENG":"You're in the hands of the Administration wherever you go in Front Bay.","TWN":"在前灣，無論你們逃到哪裡，都逃不過管理局的五指山的。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그런 말하면 누가 겁먹어? 그 관리국에서 믿고 맡긴 너희가 이런 허접인데?","JPN":"そんな言葉で誰が怖気づくと思うんだ？　その管理局が信じて任せたお前らが、こんなヘタクソなのに？","ENG":"Who'd get scared by that? The Administration put you losers in charge in the first place!","TWN":"聽到這種話有人會怕嗎？你們不是被管理局請的嗎？也不怎麼樣啊。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"풉- 풉- 선장님의 지략에 단체로 끔뻑 넘어가는 꼴이라니, 관리국의 수치네요!","JPN":"ぷーぷー船長の知略に全員騙されるなんて、管理局の恥ですね！","ENG":"Pfft! Pfft! They all fell for your trick, Captain! The Administration must be humiliated!","TWN":"噗噗，船長一句話就讓你們都啞口無言，簡直是管理局之恥！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_WATCH","text":{"KOREA":"크윽…! 저것들이!","JPN":"くっ……！　あいつら！","ENG":"Kgh...! Why those little...!","TWN":"可惡…！你們這些傢伙！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"선장- 도발은 그쯤 하고 얼른 도망치는 게 낫지 않아?","JPN":"船長ー挑発はそのくらいにして早く逃げた方がいいんじゃない？","ENG":"Captain. Shouldn't we stop provoking them and run?","TWN":"船長，別再跟他們廢話了，我們還是快逃吧？"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"잠깐만. 저기 잔뜩 화나서 몰려오는 바보들만 좀 찍고.","JPN":"ちょっと待って。あそこの怒りまくって走ってくるバカどもを撮ってから。","ENG":"Wait. I just gotta take a pic of those angry idiots running after us.","TWN":"等等，我先拍一下那些火冒三丈衝過來的笨蛋。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GUARD_FRONTBAY_COAST_SEVERAL","text":{"KOREA":"아직 저기 있다!","JPN":"あそこ、まだいる！","ENG":"They're still over there!","TWN":"人還在那裡！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GUARD_FRONTBAY_COAST_SEVERAL","text":{"KOREA":"잡아라! 놓치지 마!","JPN":"捕まえろ！　逃すな！","ENG":"Get them! Don't let them get away!","TWN":"抓住她們！別讓人給跑了！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"흐아~ 이제 안 쫓아오네요. 아슬아슬했어요.","JPN":"ひゅう～もう追いかけてきませんね。ギリギリでした。","ENG":"Phew! They're not on our tail anymore. That was close.","TWN":"呼～好像沒有再繼續追了，好險。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"푸하핫- 여기 왼쪽 녀석 좀 봐. 완전 웃긴 표정으로 찍혔네.","JPN":"キャハハッーここ、左のやつ見ろよ。ちょう変な顔になっている。","ENG":"Bah hah hah! Look at the one on the left here. That face is hilarious.","TWN":"噗哈哈，你看左邊的人，表情超好笑的。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"이번엔 너무 일을 키운 거 아냐, 선장?","JPN":"ちょっと今回はことを大きくし過ぎたんじゃないか、船長？","ENG":"Don't you think this was a bit overkill, Captain?","TWN":"船長，這次是不是有點過火？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"적당히 보석금 내고 풀려날 줄 알았는데 말이지.","JPN":"適当に金払って解放されるのかと思ったのに。","ENG":"I thought we'd get out on bail.","TWN":"我還以為只要繳個保釋金，他們就會釋放我們了吧？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"너무하네. 그렇게 세금 내듯이 달라는 대로 보석금을 내면 재미없잖아.","JPN":"ええ。素直に金を払ったらつまらないじゃん。","ENG":"C'mon. It's no fun to just pay bail like paying taxes.","TWN":"那怎麼行，如果他們跟你要保釋金你就繳，就像繳稅一樣，那有什麼好玩的？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"맞아요, 소냐! 정당하게 돈을 내는 건 낭만이 아니에요! 해적답지 못하다고요!","JPN":"そうですよ、ソーニャ！　正当にお金を払うのはロマンではありません！　海賊らしくありません！","ENG":"Yeah, Sonya! It's not the pirate dream to pay money fair and square! It's un-pirate-like!","TWN":"對啊，索妮雅！乖乖繳錢一點都不浪漫！也不符合海盜的作風！"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐, 애초에 그럴 만한 돈도 없었지만.","JPN":"まぁそもそも、そんな金もないしね。","ENG":"Well, not that I had the cash to bail you out anyway.","TWN":"更何況我們又沒有錢。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"하아…","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哀哀…"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그래서, 우리 배는 지금 어디 있어?","JPN":"で、あたしたちの船は今どこ？","ENG":"So, where's our ship right now?","TWN":"那我們船呢？現在在哪裡？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아- 그거-","JPN":"あーそれなー","ENG":"Oh, that.","TWN":"喔～船喔。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"격벽 항만 어딘가에 박혀있을 걸? 아마 되찾긴 힘들 거야.","JPN":"たぶん隔壁港湾のどこかにあるはずだよ。取り戻すのは難しいだろうね。","ENG":"It's probably lodged into a bulwark port somewhere. We won't be getting it back.","TWN":"船應該卡在隔離牆港灣的某個地方，我看是找不回來了。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"해적이 배가 없으면 어떡해? 돈도 없다며?","JPN":"海賊が船がなくてどうするんだ？　金もないんだろ？","ENG":"We're pirates. How can we not have a ship? Or any money, at that?","TWN":"海盜怎麼可已沒有船？你又說沒錢？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그야 새로 구하면 되지. 해적답게.","JPN":"そりゃまた新しく手に入れればいいんだ。海賊らしく。","ENG":"We can always get a new one. Like pirates.","TWN":"就用海盜的方式再弄一艘新的來就好啦。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"역시 선장! 무일푼 거지꼴이 된 상황에서도 다 계획이 있으시군요!","JPN":"さすが船長！　文無しの物乞い状態になってもまだ計画がおありなのですね！","ENG":"You're so wise, Captain! We're penniless and you still have a plan!","TWN":"不愧是船長！雖然窮得快被鬼抓走，但你內心早有盤算吧！"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"응? 딱히 계획은 없는데?","JPN":"ん？　別に計画なんかないけど？","ENG":"Huh? I don't have any plans, actually.","TWN":"什麼？哪有什麼盤算？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"에엑-!","JPN":"えーっ！","ENG":"Whaa–?!","TWN":"欸欸！"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"하… 하긴 계획을 세우는 건 해적스럽지 못하네요.","JPN":"た……確かに計画を立てるのは海賊らしくないですね。","ENG":"I... I guess it's not very pirate-like to make plans.","TWN":"也…也對，盤算才不是海盜的作風！"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"탈리, 바보랑 해적을 같은 취급하지 마.","JPN":"タリー、バカと海賊を同じように扱うな。","ENG":"Tallie, being a pirate is different from being an idiot.","TWN":"塔莉，你可以不要把笨蛋和海盜混為一談嗎？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"하지만 걱정 마세요!","JPN":"でも心配しないでください！","ENG":"But don't you worry!","TWN":"大家別擔心！"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"제가 금괴가 잔뜩 쌓여있는 장소를 알고 있거든요!","JPN":"私が金塊がたくさんある場所を知っています！","ENG":"I know a place that's full of gold bars!","TWN":"我知道一個滿是黃金的地方！"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"거길 털어서 목돈을 마련하자고요!","JPN":"そこを盗んで金を作りましょう！","ENG":"Let's rob the place and get some money!","TWN":"我們就去洗劫那裡湊筆錢吧！"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"설마 은행이라도 털 셈이야?","JPN":"まさか銀行強盗でもするつもり？","ENG":"Are you going to rob a bank?","TWN":"你現在是想搶劫銀行嗎？"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"훗, 그럴 리가요. 관리국은 제가 아는 비밀장소에 금괴가 있는 줄도 모를걸요?","JPN":"ふっ、まさか。管理局は私が知っている秘密場所に金塊があるとも知らないはずですよ？","ENG":"Heh, of course not. The Administration probably doesn't know about the secret place with gold bars.","TWN":"呵，怎麼可能。管理局根本不知道那個地方有藏黃金。"},"stage":{"bg":"DOCK_DAY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};